import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ScrollArea } from "@/components/ui/scroll-area";
import { format } from "date-fns";
import { Search, RefreshCw, AlertTriangle, FileText, User as UserIcon } from "lucide-react";
import { useTranslation } from "react-i18next";

interface VisitLog {
  id: string;
  visitor_id: string;
  user_id: string | null;
  user_email: string | null;
  path: string;
  search: string | null;
  status: string;
  status_code: number | null;
  error_message: string | null;
  referer: string | null;
  user_agent: string | null;
  country: string | null;
  city: string | null;
  ip: string | null;
  duration_ms: number | null;
  created_at: string;
}

const PAGE_SIZE = 50;

const statusBadge = (status: string) => {
  if (status === "404") return <Badge variant="destructive">404</Badge>;
  if (status === "error") return <Badge variant="destructive" className="bg-orange-600 hover:bg-orange-700">错误</Badge>;
  return <Badge variant="secondary">OK</Badge>;
};

const AdminVisitLogs = () => {
  const { t } = useTranslation();
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [searchTerm, setSearchTerm] = useState("");
  const [page, setPage] = useState(0);

  const { data, isLoading, refetch, isFetching } = useQuery({
    queryKey: ["admin-visit-logs", statusFilter, page],
    queryFn: async () => {
      let q = supabase
        .from("visit_logs" as any)
        .select("*", { count: "exact" })
        .order("created_at", { ascending: false })
        .range(page * PAGE_SIZE, page * PAGE_SIZE + PAGE_SIZE - 1);
      if (statusFilter !== "all") q = q.eq("status", statusFilter);
      const { data, count, error } = await q;
      if (error) throw error;
      return { rows: (data || []) as unknown as VisitLog[], total: count || 0 };
    },
    refetchInterval: 30_000,
  });

  // Stats (last 24h)
  const { data: stats } = useQuery({
    queryKey: ["admin-visit-logs-stats"],
    queryFn: async () => {
      const since = new Date(Date.now() - 24 * 3600 * 1000).toISOString();
      const [{ count: total }, { count: errors }, { count: notFound }] = await Promise.all([
        supabase.from("visit_logs" as any).select("*", { count: "exact", head: true }).gte("created_at", since),
        supabase.from("visit_logs" as any).select("*", { count: "exact", head: true }).gte("created_at", since).eq("status", "error"),
        supabase.from("visit_logs" as any).select("*", { count: "exact", head: true }).gte("created_at", since).eq("status", "404"),
      ]);
      return { total: total || 0, errors: errors || 0, notFound: notFound || 0 };
    },
    refetchInterval: 60_000,
  });

  const filtered = useMemo(() => {
    if (!data?.rows) return [];
    if (!searchTerm.trim()) return data.rows;
    const s = searchTerm.toLowerCase();
    return data.rows.filter(
      (r) =>
        r.path.toLowerCase().includes(s) ||
        r.user_email?.toLowerCase().includes(s) ||
        r.error_message?.toLowerCase().includes(s) ||
        r.visitor_id.toLowerCase().includes(s)
    );
  }, [data?.rows, searchTerm]);

  const totalPages = Math.ceil((data?.total || 0) / PAGE_SIZE);

  return (
    <div className="container mx-auto p-4 md:p-6 space-y-4">
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h1 className="text-2xl font-bold flex items-center gap-2">
          <FileText className="h-6 w-6" />
          访问日志
        </h1>
        <Button onClick={() => refetch()} disabled={isFetching} size="sm" variant="outline">
          <RefreshCw className={`h-4 w-4 mr-2 ${isFetching ? "animate-spin" : ""}`} />
          刷新
        </Button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-muted-foreground">24小时访问总数</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.total ?? "—"}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-muted-foreground">24小时 404</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-destructive">{stats?.notFound ?? "—"}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-muted-foreground flex items-center gap-1">
              <AlertTriangle className="h-4 w-4" /> 24小时错误
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-orange-600">{stats?.errors ?? "—"}</div>
          </CardContent>
        </Card>
      </div>

      {/* Filters */}
      <Card>
        <CardContent className="pt-4 flex flex-wrap gap-3 items-center">
          <div className="relative flex-1 min-w-[240px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="搜索路径 / 邮箱 / 错误 / visitor_id..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-9"
            />
          </div>
          <Select value={statusFilter} onValueChange={(v) => { setStatusFilter(v); setPage(0); }}>
            <SelectTrigger className="w-[160px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">全部状态</SelectItem>
              <SelectItem value="ok">成功 (OK)</SelectItem>
              <SelectItem value="404">404 未找到</SelectItem>
              <SelectItem value="error">错误</SelectItem>
            </SelectContent>
          </Select>
        </CardContent>
      </Card>

      {/* Table */}
      <Card>
        <CardContent className="p-0">
          <ScrollArea className="h-[600px]">
            <Table>
              <TableHeader className="sticky top-0 bg-background z-10">
                <TableRow>
                  <TableHead className="w-[150px]">时间</TableHead>
                  <TableHead className="w-[80px]">状态</TableHead>
                  <TableHead>路径</TableHead>
                  <TableHead className="w-[200px]">用户</TableHead>
                  <TableHead className="w-[120px]">位置</TableHead>
                  <TableHead className="w-[80px]">停留</TableHead>
                  <TableHead>错误信息</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading ? (
                  <TableRow>
                    <TableCell colSpan={7} className="text-center py-10 text-muted-foreground">
                      加载中...
                    </TableCell>
                  </TableRow>
                ) : filtered.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={7} className="text-center py-10 text-muted-foreground">
                      暂无数据
                    </TableCell>
                  </TableRow>
                ) : (
                  filtered.map((log) => (
                    <TableRow key={log.id} className={log.status !== "ok" ? "bg-destructive/5" : ""}>
                      <TableCell className="text-xs whitespace-nowrap">
                        {format(new Date(log.created_at), "MM-dd HH:mm:ss")}
                      </TableCell>
                      <TableCell>{statusBadge(log.status)}</TableCell>
                      <TableCell className="font-mono text-xs max-w-[300px] truncate" title={log.path + (log.search || "")}>
                        {log.path}
                        {log.search && <span className="text-muted-foreground">{log.search}</span>}
                      </TableCell>
                      <TableCell className="text-xs">
                        {log.user_email ? (
                          <div className="flex items-center gap-1">
                            <UserIcon className="h-3 w-3" />
                            <span className="truncate max-w-[160px]" title={log.user_email}>{log.user_email}</span>
                          </div>
                        ) : (
                          <span className="text-muted-foreground" title={log.visitor_id}>
                            访客 {log.visitor_id.slice(0, 8)}
                          </span>
                        )}
                      </TableCell>
                      <TableCell className="text-xs text-muted-foreground">
                        {[log.city, log.country].filter(Boolean).join(", ") || "—"}
                      </TableCell>
                      <TableCell className="text-xs text-muted-foreground">
                        {log.duration_ms != null ? `${(log.duration_ms / 1000).toFixed(1)}s` : "—"}
                      </TableCell>
                      <TableCell className="text-xs text-destructive max-w-[300px] truncate" title={log.error_message || ""}>
                        {log.error_message || "—"}
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </ScrollArea>
        </CardContent>
      </Card>

      {/* Pagination */}
      <div className="flex items-center justify-between text-sm">
        <span className="text-muted-foreground">
          共 {data?.total ?? 0} 条 · 第 {page + 1} / {Math.max(totalPages, 1)} 页
        </span>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" disabled={page === 0} onClick={() => setPage((p) => p - 1)}>
            上一页
          </Button>
          <Button
            variant="outline"
            size="sm"
            disabled={page + 1 >= totalPages}
            onClick={() => setPage((p) => p + 1)}
          >
            下一页
          </Button>
        </div>
      </div>
    </div>
  );
};

export default AdminVisitLogs;
